const loadConfig = async () => {
  try {
    window.__API_BASE = window.__API_BASE || '%REACT_APP_API_URL%';
    const response = await fetch(`${window.__API_BASE}/config`);
    const config = await response.json();
    console.log('[Config]', config);
    return config;
  } catch (err) {
    console.error('Failed to load config:', err);
    return null;
  }
};
// --- CONFIG & CONTEXT ---
const DEFAULT_TENANTS = {
  CLIENT_001: {
    id: 'CLIENT_001',
    clientId: process.env.REACT_APP_CLIENT1_ID || 'CLIENT_001',
    name: process.env.REACT_APP_CLIENT1_NAME || 'Atul Logistics',
    role: 'Client',
  },
};

const buildTenants = () => {
  const raw = process.env.REACT_APP_TENANTS_JSON || '';
  let input = null;
  if (raw) {
    try { input = JSON.parse(raw); } catch (e) { input = null; }
  }

  const toRecord = (items) => {
    const record = {};
    items.forEach((item) => {
      const id = item?.id || item?.clientId || `tenant_${Object.keys(record).length + 1}`;
      record[id] = {
        id,
        clientId: item?.clientId || id,
        name: item?.name || id,
        role: item?.role || 'Client',
      };
    });
    return record;
  };

  let tenants = DEFAULT_TENANTS;
  if (Array.isArray(input) && input.length > 0) tenants = toRecord(input);
  else if (input && typeof input === 'object') tenants = toRecord(Object.values(input));

  Object.values(tenants).forEach((t) => {
    const label = t.name || 'Client';
    t.logoInitials = label.split(' ').map(s => s[0]).slice(0, 2).join('').toUpperCase();
  });
  return tenants;
};

const TENANTS = buildTenants();
const TenantContext = createContext(null);
const useTenant = () => {
  const context = useContext(TenantContext);
  if (!context) throw new Error('useTenant must be used within a TenantProvider');
  return context;
};

