import React from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap, CircleMarker, Polyline } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import markerIcon2x from 'leaflet/dist/images/marker-icon-2x.png';
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';

// Fix default marker icon paths for bundlers (CRA/Vite)
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: markerIcon2x,
  iconUrl: markerIcon,
  shadowUrl: markerShadow,
});

const VehicleTracker = ({ vehicles = [], highlightNumbers = [], trackedPath = [], trackingVehicleId = null, trackLoading = false, trackError = null }) => {
  console.log('Rendering VehicleTracker with', vehicles.length, 'vehicles', 'highlight=', highlightNumbers, 'trackedPath=', Array.isArray(trackedPath) ? trackedPath.length : trackedPath, 'loading=', trackLoading);

  // State for reversed path toggle
  const [isReversed, setIsReversed] = React.useState(false);
  
  // State for playback animation
  const [isPlaying, setIsPlaying] = React.useState(false);
  const [currentPointIndex, setCurrentPointIndex] = React.useState(0);
  const [playbackSpeed, setPlaybackSpeed] = React.useState(1); // 1x, 2x, 5x, 10x
  
  // Reverse the path for display if toggle is on
  const displayPath = React.useMemo(() => {
    if (!Array.isArray(trackedPath) || trackedPath.length === 0) return [];
    return isReversed ? [...trackedPath].reverse() : trackedPath;
  }, [trackedPath, isReversed]);
  
  // Animation loop for marker movement
  React.useEffect(() => {
    if (!isPlaying || displayPath.length === 0) return;
    
    const interval = setInterval(() => {
      setCurrentPointIndex(prev => {
        if (prev >= displayPath.length - 1) {
          setIsPlaying(false);
          return prev;
        }
        return prev + 1;
      });
    }, 500 / playbackSpeed); // Update every 500ms, adjusted by speed
    
    return () => clearInterval(interval);
  }, [isPlaying, displayPath.length, playbackSpeed]);

  // choose center from first vehicle if available
  const first = vehicles.find(v => v && v.lat != null && v.lng != null);
  const center = first ? [Number(first.lat), Number(first.lng)] : [20.5937, 78.9629];
  const zoom = first ? 8 : 5;

  function FitBounds({ vehicles, trackedPath }) {
    const map = useMap();
    React.useEffect(() => {
      let coords = vehicles
        .filter((v) => v && v.lat != null && v.lng != null)
        .map((v) => [Number(v.lat), Number(v.lng)]);
      
      // If we have a tracked path, include those bounds too
      if (Array.isArray(trackedPath) && trackedPath.length > 0) {
        const pathCoords = trackedPath
          .map(p => [Number(p.lat), Number(p.lng)])
          .filter(c => !isNaN(c[0]) && !isNaN(c[1]));
        coords = [...coords, ...pathCoords];
      }
      
      if (coords.length === 0) return;
      try {
        map.fitBounds(coords, { padding: [50, 50] });
      } catch (e) {
        // ignore fit errors
      }
    }, [vehicles, trackedPath, map]);
    return null;
  }

  // deduplicate vehicles by id or number to avoid duplicate markers
  const uniqueVehicles = React.useMemo(() => {
    const m = new Map();
    (vehicles || []).forEach(v => {
      if (!v) return;
      const key = v.id ?? v.number ?? `${v.lat}:${v.lng}`;
      if (!m.has(key) && v.lat != null && v.lng != null) m.set(key, v);
    });
    return Array.from(m.values());
  }, [vehicles]);

  return (
    <div style={{ width: '100%', height: '100%' }}>
      <MapContainer 
        center={center}
        zoom={zoom}
        scrollWheelZoom={true}
        style={{ height: '100%', width: '100%' }}
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />

        <FitBounds vehicles={uniqueVehicles} trackedPath={displayPath} />
        {uniqueVehicles.map(v => {
          const isHighlighted = highlightNumbers.includes(v.number);
          if (isHighlighted) {
            return (
                <React.Fragment key={`h-${v.id || v.number}`}>
                  <Marker position={[Number(v.lat), Number(v.lng)]}>
                    <Popup>
                      <div style={{ fontSize: 12 }}>
                        <strong>{v.number || v.vehicleNumber || 'Vehicle'}</strong>
                        <div style={{ fontSize: 11 }}>{v.driver || v.driverName || ''}</div>
                        <div style={{ fontSize: 11, marginTop: 4, color: '#666' }}>
                          POI: {v.poiName || 'Outside'}
                        </div>
                        <div style={{ fontSize: 11, marginTop: 4, color: '#d6336c' }}>
                          STP: {v.stoppageAll || '-'}
                        </div>
                        {v.lastUpdate && (
                          <div style={{ fontSize: 10, marginTop: 2, color: '#666' }}>
                            {new Date(v.lastUpdate).toLocaleString()}
                          </div>
                        )}
                      </div>
                    </Popup>
                  </Marker>
                  <CircleMarker
                    center={[Number(v.lat), Number(v.lng)]}
                    pathOptions={{ color: 'red', fillColor: 'red', fillOpacity: 0.6 }}
                    radius={10}
                  />
                </React.Fragment>
            );
          }
          return (
            <Marker key={v.id || v.number || Math.random()} position={[Number(v.lat), Number(v.lng)]}>
              <Popup>
                <div style={{ fontSize: 12 }}>
                  <strong>{v.number || v.vehicleNumber || 'Vehicle'}</strong>
                  <div style={{ fontSize: 11 }}>{v.driver || v.driverName || ''}</div>
                  <div style={{ fontSize: 11, marginTop: 4, color: '#666' }}>
                    POI: {v.poiName || 'Outside'}
                  </div>
                  <div style={{ fontSize: 11, marginTop: 4, color: '#d6336c' }}>
                    STP: {v.stoppageAll || '-'}
                  </div>
                  {v.lastUpdate && (
                    <div style={{ fontSize: 10, marginTop: 2, color: '#666' }}>
                      {new Date(v.lastUpdate).toLocaleString()}
                    </div>
                  )}
                  {v._stopped && v.stopTime && (
                    <div style={{ fontSize: 11, marginTop: 4, color: '#d6336c' }}>
                      Stopped: {v.stopTime}
                    </div>
                  )}
                </div>
              </Popup>
            </Marker>
          );
        })}
        {/* render tracked path if provided */}
        {Array.isArray(displayPath) && displayPath.length > 0 && (
          <>
            {/* Animated vehicle marker during playback */}
            {isPlaying && displayPath[currentPointIndex] && (
              <CircleMarker
                center={[Number(displayPath[currentPointIndex].lat), Number(displayPath[currentPointIndex].lng)]}
                radius={8}
                pathOptions={{ color: '#f59e0b', fillColor: '#fbbf24', fillOpacity: 1, weight: 3 }}
              >
                <Popup>
                  <div style={{ fontSize: 11, fontWeight: 'bold' }}>
                    🚗 Current Position
                    <div style={{ marginTop: 4 }}>{new Date(displayPath[currentPointIndex].ts || displayPath[currentPointIndex].gps_time).toLocaleString()}</div>
                    <div style={{ marginTop: 2, fontSize: 10 }}>
                      Point {currentPointIndex + 1} / {displayPath.length}
                    </div>
                  </div>
                </Popup>
              </CircleMarker>
            )}
            
            {/* Trail showing path already traveled during playback */}
            {isPlaying && currentPointIndex > 0 && (
              <Polyline
                positions={displayPath.slice(0, currentPointIndex + 1).map(p => [Number(p.lat), Number(p.lng)])}
                pathOptions={{ color: '#10b981', weight: 4, opacity: 0.8, dashArray: 'none' }}
              />
            )}
            
            {/* Remaining path (future route) in lighter blue */}
            {isPlaying && currentPointIndex < displayPath.length - 1 && (
              <Polyline
                positions={displayPath.slice(currentPointIndex).map(p => [Number(p.lat), Number(p.lng)])}
                pathOptions={{ color: '#3b82f6', weight: 2, opacity: 0.4, dashArray: '4, 4' }}
              />
            )}
            
            {/* Full path shown when not playing */}
            {!isPlaying && (
              <Polyline
                positions={displayPath.map(p => [Number(p.lat), Number(p.lng)])}
                pathOptions={{ color: '#1d4ed8', weight: 3, opacity: 0.6, dashArray: '4, 4' }}
              />
            )}
            
            {/* Detect stops: identify points where vehicle stayed (same location within 50m or 30+ min gap) */}
            {(() => {
              const stops = [];
              const MIN_STOP_TIME_MINUTES = 30;
              const MAX_MOVE_DISTANCE_METERS = 0.0005; // ~50 meters in degrees
              
              for (let i = 1; i < displayPath.length; i++) {
                const prev = displayPath[i - 1];
                const curr = displayPath[i];
                const prevTime = new Date(prev.ts || prev.gps_time);
                const currTime = new Date(curr.ts || curr.gps_time);
                const timeDiffMinutes = (currTime - prevTime) / (1000 * 60);
                
                const latDiff = Math.abs(Number(curr.lat) - Number(prev.lat));
                const lngDiff = Math.abs(Number(curr.lng) - Number(prev.lng));
                const maxDiff = Math.max(latDiff, lngDiff);
                
                // If time gap is large or vehicle barely moved, it's a stop
                if (timeDiffMinutes >= MIN_STOP_TIME_MINUTES || maxDiff < MAX_MOVE_DISTANCE_METERS) {
                  stops.push({
                    index: i - 1,
                    pos: [Number(displayPath[i - 1].lat), Number(displayPath[i - 1].lng)],
                    time: displayPath[i - 1].ts || displayPath[i - 1].gps_time,
                    duration: timeDiffMinutes
                  });
                  i++; // skip next to avoid duplicate stops
                }
              }
              return stops;
            })().map((stop, idx) => (
              <CircleMarker
                key={`stop-${idx}`}
                center={stop.pos}
                radius={8}
                pathOptions={{ color: '#dc2626', fillColor: '#ef4444', fillOpacity: 0.95, weight: 3 }}
              >
                <Popup>
                  <div style={{ fontSize: 11, fontWeight: 'bold' }}>
                    🛑 Stop Point {idx + 1}
                    <div style={{ marginTop: 4 }}>{new Date(stop.time).toLocaleString()}</div>
                    {stop.duration >= 30 && <div style={{ marginTop: 4, color: '#dc2626' }}>⏱️ Duration: {Math.round(stop.duration)} min</div>}
                  </div>
                </Popup>
              </CircleMarker>
            ))}
            
            {/* Draw location dots for each track point - make them larger and more visible */}
            {displayPath.map((point, idx) => {
              // Render every point (or skip some if too many to avoid clutter)
              const skipInterval = displayPath.length > 200 ? Math.floor(displayPath.length / 50) : 1;
              if (idx % skipInterval !== 0 && idx !== displayPath.length - 1 && idx !== 0) return null;
              
              return (
                <CircleMarker
                  key={`track-${idx}`}
                  center={[Number(point.lat), Number(point.lng)]}
                  radius={5}
                  pathOptions={{ color: '#2563eb', fillColor: '#3b82f6', fillOpacity: 0.85, weight: 2 }}
                >
                  <Popup>
                    <div style={{ fontSize: 11 }}>
                      <strong>Point {isReversed ? displayPath.length - idx : idx + 1} / {displayPath.length}</strong>
                      <div style={{ marginTop: 4, fontWeight: 'bold' }}>
                        📍 {Number(point.lat).toFixed(6)}, {Number(point.lng).toFixed(6)}
                      </div>
                      <div style={{ marginTop: 4, color: '#666' }}>
                        🕐 {new Date(point.ts || point.gps_time).toLocaleString()}
                      </div>
                    </div>
                  </Popup>
                </CircleMarker>
              );
            })}
            
            {/* start/end markers - larger and more visible */}
            {displayPath[0] && (
              <CircleMarker key={`start-${trackingVehicleId || 'trk'}`} center={[Number(displayPath[0].lat), Number(displayPath[0].lng)]} radius={10} pathOptions={{ color: '#16a34a', fillColor: '#22c55e', fillOpacity: 1, weight: 3 }}>
                <Popup>
                  <div style={{ fontSize: 12, fontWeight: 'bold' }}>
                    🟢 {isReversed ? 'End Point' : 'Start Point'}
                    <div style={{ marginTop: 4 }}>{new Date(displayPath[0].ts || displayPath[0].gps_time).toLocaleString()}</div>
                    <div style={{ marginTop: 2, fontSize: 10 }}>
                      📍 {Number(displayPath[0].lat).toFixed(6)}, {Number(displayPath[0].lng).toFixed(6)}
                    </div>
                  </div>
                </Popup>
              </CircleMarker>
            )}
            {displayPath[displayPath.length - 1] && (
              <CircleMarker key={`end-${trackingVehicleId || 'trk'}`} center={[Number(displayPath[displayPath.length - 1].lat), Number(displayPath[displayPath.length - 1].lng)]} radius={10} pathOptions={{ color: '#dc2626', fillColor: '#ef4444', fillOpacity: 1, weight: 3 }}>
                <Popup>
                  <div style={{ fontSize: 12, fontWeight: 'bold' }}>
                    🔴 {isReversed ? 'Start Point' : 'End Point'}
                    <div style={{ marginTop: 4 }}>{new Date(displayPath[displayPath.length - 1].ts || displayPath[displayPath.length - 1].gps_time).toLocaleString()}</div>
                    <div style={{ marginTop: 2, fontSize: 10 }}>
                      📍 {Number(displayPath[displayPath.length - 1].lat).toFixed(6)}, {Number(displayPath[displayPath.length - 1].lng).toFixed(6)}
                    </div>
                  </div>
                </Popup>
              </CircleMarker>
            )}
          </>
        )}
      </MapContainer>
      {/* Playback controls and time display - shown when track loaded */}
      {Array.isArray(trackedPath) && trackedPath.length > 0 && (
        <div style={{ 
          position: 'absolute', 
          bottom: 12, 
          left: 12, 
          right: 12, 
          zIndex: 9999,
          background: 'rgba(255, 255, 255, 0.95)',
          padding: '12px',
          borderRadius: '8px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          backdropFilter: 'blur(4px)'
        }}>
          {/* Time display */}
          <div style={{ 
            marginBottom: '8px', 
            fontSize: '12px', 
            fontWeight: 'bold',
            textAlign: 'center',
            color: '#1f2937'
          }}>
            {isPlaying && displayPath[currentPointIndex] ? (
              <>
                🕐 {new Date(displayPath[currentPointIndex].ts || displayPath[currentPointIndex].gps_time).toLocaleString()}
                <span style={{ marginLeft: '8px', color: '#666', fontSize: '11px' }}>
                  ({currentPointIndex + 1}/{displayPath.length})
                </span>
              </>
            ) : (
              <>
                {displayPath.length} GPS points available
              </>
            )}
          </div>
          
          {/* Progress bar */}
          <div style={{ marginBottom: '8px' }}>
            <div style={{ 
              width: '100%', 
              height: '4px', 
              background: '#e5e7eb', 
              borderRadius: '2px',
              overflow: 'hidden'
            }}>
              <div style={{
                height: '100%',
                background: '#f59e0b',
                width: `${displayPath.length > 0 ? (currentPointIndex / (displayPath.length - 1)) * 100 : 0}%`,
                transition: 'width 0.3s ease'
              }} />
            </div>
          </div>
          
          {/* Controls */}
          <div style={{ display: 'flex', gap: '6px', alignItems: 'center', justifyContent: 'center', flexWrap: 'wrap' }}>
            {/* Play/Pause button */}
            <button 
              onClick={() => setIsPlaying(!isPlaying)}
              disabled={displayPath.length === 0}
              style={{
                padding: '6px 10px',
                fontSize: '12px',
                borderRadius: '4px',
                border: 'none',
                background: isPlaying ? '#ef4444' : '#3b82f6',
                color: 'white',
                cursor: 'pointer',
                fontWeight: 'bold',
                transition: 'background 0.2s'
              }}
              title={isPlaying ? 'Pause animation' : 'Play animation'}
            >
              {isPlaying ? '⏸ Pause' : '▶ Play'}
            </button>
            
            {/* Reset button */}
            <button
              onClick={() => {
                setCurrentPointIndex(0);
                setIsPlaying(false);
              }}
              disabled={displayPath.length === 0}
              style={{
                padding: '6px 10px',
                fontSize: '12px',
                borderRadius: '4px',
                border: 'none',
                background: '#6b7280',
                color: 'white',
                cursor: 'pointer',
                fontWeight: 'bold',
                transition: 'background 0.2s'
              }}
              title="Reset to start"
            >
              ⊚ Reset
            </button>
            
            {/* Speed controls */}
            <div style={{ display: 'flex', gap: '4px', alignItems: 'center' }}>
              <span style={{ fontSize: '11px', color: '#666', fontWeight: 'bold' }}>Speed:</span>
              {[1, 2, 5, 10].map(speed => (
                <button
                  key={speed}
                  onClick={() => setPlaybackSpeed(speed)}
                  style={{
                    padding: '4px 8px',
                    fontSize: '11px',
                    borderRadius: '3px',
                    border: playbackSpeed === speed ? 'none' : '1px solid #d1d5db',
                    background: playbackSpeed === speed ? '#10b981' : '#f3f4f6',
                    color: playbackSpeed === speed ? 'white' : '#1f2937',
                    cursor: 'pointer',
                    fontWeight: 'bold',
                    transition: 'background 0.2s'
                  }}
                  title={`${speed}x playback speed`}
                >
                  {speed}x
                </button>
              ))}
            </div>
          </div>
        </div>
      )}
      
      {/* Reverse button - moved to top right */}
      {trackLoading && (
        <div style={{ position: 'absolute', left: 12, top: 12, zIndex: 9999 }}>
          <div className="bg-white/90 px-3 py-2 rounded-md shadow">Loading track...</div>
        </div>
      )}
      {trackError && (
        <div style={{ position: 'absolute', left: 12, top: 12, zIndex: 9999 }}>
          <div className="bg-rose-50 text-rose-700 px-3 py-2 rounded-md shadow">{trackError}</div>
        </div>
      )}
      {Array.isArray(trackedPath) && trackedPath.length > 0 && (
        <div style={{ position: 'absolute', right: 12, top: 12, zIndex: 9999 }}>
          <button 
            onClick={() => setIsReversed(!isReversed)}
            className={`px-3 py-2 rounded-md font-semibold text-sm transition-all shadow ${
              isReversed 
                ? 'bg-amber-500 text-white hover:bg-amber-600' 
                : 'bg-white text-slate-700 hover:bg-slate-100 border border-slate-200'
            }`}
            title={isReversed ? 'Show original path direction' : 'Reverse path direction'}
          >
            {isReversed ? '⟲ Reversed' : '↻ Reverse'}
          </button>
        </div>
      )}
    </div>
  );
};

export default VehicleTracker;